import pandas as pd
actions_in_use = {"Sum"}
actions_without_prefix = {"First", "Last", "Sum"}

def rename_column(col_name):
    last_underscore_index = col_name.rfind("_")
    if last_underscore_index != -1:
        first_half = col_name[:last_underscore_index]
        second_half = col_name[last_underscore_index + 1:]

        if second_half == "Concat":
            return first_half
        elif len(actions_in_use) == 1 and actions_in_use.issubset(actions_without_prefix) and second_half in actions_without_prefix:
            return first_half
        elif second_half in actions_in_use:
            return f"{second_half}_{first_half}"
        else:
            return col_name
    else:
        return col_name

renamed_columns = [rename_column(col_name) for col_name in in0.columns]

valid_columns = [
    (orig_col, renamed_col)
    for orig_col, renamed_col in zip(in0.columns, renamed_columns)
    if not renamed_col.endswith("_dummy_")
]

filtered_dataframe = in0[[orig_col for orig_col, _ in valid_columns]].copy()
valid_renamed_columns = [renamed_col for _, renamed_col in valid_columns]

filtered_dataframe.columns = valid_renamed_columns
out0 = filtered_dataframe
